/**
 * MMS TypeScript Fallback Optimizer
 *
 * Greedy algorithm implementation for train-to-route assignment.
 * Used as fallback when C++ OR-Tools optimizer is unavailable,
 * times out, or returns INFEASIBLE.
 *
 * Algorithm:
 * 1. Sort routes by required trains (descending) - prioritize high-demand routes
 * 2. Sort trains by mileage balance (ascending) - prioritize under-utilized trains
 * 3. For each route, greedily assign compatible fit trains
 * 4. Generate explanation traces for each assignment
 *
 * @see specs/002-architecture.md Section 2.4
 * @see specs/004-domain-services.md Section 4.3.2
 */

import { logger } from '../lib/logging/logger';
import { withSpan } from '../lib/tracing';
import {
  type OptimizerFullInput,
  type OptimizerFullResult,
  type Assignment,
  type UnassignedTrain,
  type MaterialWarning,
  type ExplanationTrace,
  type OptimizerTrainInput,
  type OptimizerRouteInput,
  type ResultSummary,
} from './types';

// =============================================================================
// Fallback Optimizer
// =============================================================================

/**
 * TypeScript greedy fallback optimizer
 *
 * Provides a reasonable solution when the C++ optimizer is unavailable.
 * Prioritizes mileage balancing while respecting all hard constraints.
 */
export class FallbackOptimizer {
  private readonly log = logger.child({ service: 'FallbackOptimizer' });

  /**
   * Run the greedy optimization algorithm
   */
  async optimize(input: OptimizerFullInput): Promise<OptimizerFullResult> {
    return withSpan('optimizer.fallback.optimize', async (span) => {
      const startTime = Date.now();

      span.setAttribute('requestId', input.requestId);
      span.setAttribute('trainCount', input.trains.length);
      span.setAttribute('routeCount', input.routes.length);
      span.setAttribute('hardConstraintCount', input.hardConstraints.length);
      span.setAttribute('softConstraintCount', input.softConstraints.length);

      this.log.info(
        {
          requestId: input.requestId,
          trainCount: input.trains.length,
          routeCount: input.routes.length,
        },
        'Starting fallback optimization'
      );

      const assignments: Assignment[] = [];
      const unassigned: UnassignedTrain[] = [];
      const materialWarnings: MaterialWarning[] = [];
      const assignedTrainIds = new Set<string>();
      const softConstraintBreakdown: Record<string, number> = {};

      // Build lookup maps for efficiency
      const unavailableTrainIds = this.getUnavailableTrainIds(input);
      const trainConstraintMap = this.buildTrainConstraintMap(input);
      const routeCompatibilityMap = this.buildRouteCompatibilityMap(input);

      // Sort routes by required trains (descending) - prioritize high-demand routes
      const sortedRoutes = [...input.routes].sort(
        (a, b) => b.requiredTrains - a.requiredTrains
      );

      // Sort trains by mileage balance - prioritize under-utilized trains
      const sortedTrains = this.getSortedTrains(input.trains);

      // Check material warnings for pending PMs
      materialWarnings.push(...this.checkMaterialWarnings(input));

      // Greedy assignment
      for (const route of sortedRoutes) {
        let assignedCount = 0;

        for (const train of sortedTrains) {
          if (assignedCount >= route.requiredTrains) break;
          if (assignedTrainIds.has(train.id)) continue;

          // Check hard constraints
          const blockingReason = this.checkHardConstraints(
            train,
            route,
            input,
            unavailableTrainIds,
            trainConstraintMap,
            routeCompatibilityMap
          );

          if (blockingReason) {
            continue;
          }

          // Check fleet compatibility
          if (
            route.allowedFleetIds.length > 0 &&
            !route.allowedFleetIds.includes(train.fleetId)
          ) {
            continue;
          }

          // Assign train to route
          const explanation = this.generateExplanation(train, route, input);
          const score = this.calculateScore(train, route, input, explanation);

          // Track soft constraint penalties
          for (const exp of explanation) {
            if (exp.constraintType === 'SOFT') {
              const key = exp.constraintName;
              softConstraintBreakdown[key] =
                (softConstraintBreakdown[key] || 0) + Math.abs(exp.impact);
            }
          }

          assignments.push({
            trainId: train.id,
            routeId: route.id,
            score,
            explanation,
          });

          assignedTrainIds.add(train.id);
          assignedCount++;
        }

        // Record route shortfall
        if (assignedCount < route.requiredTrains) {
          unassigned.push({
            routeId: route.id,
            shortfall: route.requiredTrains - assignedCount,
            reason: 'Insufficient fit trains available for route requirements',
            blockingConstraints: [`Required: ${route.requiredTrains}, Assigned: ${assignedCount}`],
          });
        }
      }

      // Record unassigned trains with reasons
      for (const train of input.trains) {
        if (assignedTrainIds.has(train.id)) continue;

        const reason = this.findBlockingReason(
          train,
          input,
          unavailableTrainIds,
          trainConstraintMap
        );

        unassigned.push({
          trainId: train.id,
          reason,
          blockingConstraints: this.getBlockingConstraints(train, input, trainConstraintMap),
        });
      }

      // Validate service demand
      this.validateServiceDemand(input, assignments, unassigned);

      const solveTimeMs = Date.now() - startTime;

      const summary: ResultSummary = {
        totalPenalty: this.calculateTotalPenalty(assignments),
        trainsAssigned: assignments.length,
        trainsUnassigned: input.trains.length - assignments.length,
        softConstraintBreakdown,
        materialBlocks: materialWarnings.filter(
          (w) => w.status === 'UNAVAILABLE'
        ).length,
      };

      span.setAttribute('status', 'FALLBACK');
      span.setAttribute('trainsAssigned', summary.trainsAssigned);
      span.setAttribute('trainsUnassigned', summary.trainsUnassigned);
      span.setAttribute('solveTimeMs', solveTimeMs);

      this.log.info(
        {
          requestId: input.requestId,
          status: 'FALLBACK',
          trainsAssigned: summary.trainsAssigned,
          trainsUnassigned: summary.trainsUnassigned,
          solveTimeMs,
        },
        'Fallback optimization complete'
      );

      return {
        type: 'RESULT',
        requestId: input.requestId,
        status: 'FALLBACK',
        solveTimeMs,
        assignments,
        unassigned,
        materialWarnings,
        summary,
      };
    });
  }

  /**
   * Get sorted trains by mileage balance (under-utilized first)
   */
  private getSortedTrains(trains: OptimizerTrainInput[]): OptimizerTrainInput[] {
    return [...trains]
      .filter((t) => t.fitnessStatus === 'FIT')
      .sort((a, b) => {
        // Prioritize under-utilized trains (lower current mileage vs target)
        const aBalance = a.currentMileageKm - a.targetMileageKm;
        const bBalance = b.currentMileageKm - b.targetMileageKm;
        return aBalance - bBalance;
      });
  }

  /**
   * Get set of unavailable train IDs from events
   */
  private getUnavailableTrainIds(input: OptimizerFullInput): Set<string> {
    const unavailable = new Set<string>();

    if (input.unavailabilityEvents) {
      for (const event of input.unavailabilityEvents) {
        if (event.status === 'ACTIVE' && event.blocksRunAssignment) {
          unavailable.add(event.trainId);
        }
      }
    }

    return unavailable;
  }

  /**
   * Build map of train ID to hard constraints
   */
  private buildTrainConstraintMap(
    input: OptimizerFullInput
  ): Map<string, string[]> {
    const map = new Map<string, string[]>();

    for (const constraint of input.hardConstraints) {
      const existing = map.get(constraint.trainId) || [];
      existing.push(constraint.description);
      map.set(constraint.trainId, existing);
    }

    return map;
  }

  /**
   * Build map of train+route to compatibility info
   */
  private buildRouteCompatibilityMap(
    input: OptimizerFullInput
  ): Map<string, boolean> {
    const map = new Map<string, boolean>();

    if (input.routeCompatibility) {
      for (const compat of input.routeCompatibility) {
        if (compat.trainId) {
          const key = `${compat.trainId}:${compat.routeId}`;
          map.set(key, compat.isCompatible);
        }
      }
    }

    return map;
  }

  /**
   * Check hard constraints for a train-route pair
   * Returns blocking reason or null if valid
   */
  private checkHardConstraints(
    train: OptimizerTrainInput,
    route: OptimizerRouteInput,
    input: OptimizerFullInput,
    unavailableTrainIds: Set<string>,
    trainConstraintMap: Map<string, string[]>,
    routeCompatibilityMap: Map<string, boolean>
  ): string | null {
    // Check fitness status
    if (train.fitnessStatus !== 'FIT') {
      return `Train is ${train.fitnessStatus}`;
    }

    // Check unavailability events
    if (unavailableTrainIds.has(train.id)) {
      const event = input.unavailabilityEvents?.find(
        (e) => e.trainId === train.id && e.status === 'ACTIVE'
      );
      return `Train unavailable: ${event?.eventType || 'Unknown'} - ${
        event?.description || event?.externalReference || 'No details'
      }`;
    }

    // Check explicit hard constraints
    const constraints = trainConstraintMap.get(train.id);
    if (constraints && constraints.length > 0) {
      return constraints[0];
    }

    // Check route compatibility
    const compatKey = `${train.id}:${route.id}`;
    if (routeCompatibilityMap.has(compatKey) && !routeCompatibilityMap.get(compatKey)) {
      const compat = input.routeCompatibility?.find(
        (c) => c.trainId === train.id && c.routeId === route.id
      );
      return `Route incompatible: ${compat?.constraintType || 'Technical'} - ${
        compat?.restrictionReason || 'Restriction'
      }`;
    }

    // Check pending PMs due today that block assignment
    const today = input.assignmentDate;
    if (input.pendingPms) {
      for (const pm of input.pendingPms) {
        if (pm.trainId === train.id && pm.targetDate <= today) {
          // Check if blocking materials are unavailable
          const hasBlockingMaterial = pm.requiredMaterials.some((mat) => {
            if (mat.criticality !== 'BLOCKING') return false;

            const position = input.materialPositions?.find(
              (p) =>
                p.partNumber === mat.partNumber &&
                p.depotId === train.homeDepotId
            );

            return !position || position.quantityAvailable < mat.quantity;
          });

          if (!hasBlockingMaterial) {
            return `PM ${pm.pmType} due today - train needs maintenance`;
          }
        }
      }
    }

    return null;
  }

  /**
   * Generate explanation traces for an assignment
   */
  private generateExplanation(
    train: OptimizerTrainInput,
    route: OptimizerRouteInput,
    input: OptimizerFullInput
  ): ExplanationTrace[] {
    const explanation: ExplanationTrace[] = [];
    const verbosity = input.config.explanationVerbosity;

    // Mileage balance explanation
    const mileageBalance = train.currentMileageKm - train.targetMileageKm;
    const mileageImpact =
      (Math.abs(mileageBalance) / 1000) *
      input.config.softConstraintPenalties.mileageImbalance;

    explanation.push({
      constraintType: 'SOFT',
      constraintName: 'MILEAGE_BALANCE',
      impact: mileageBalance < 0 ? -mileageImpact : mileageImpact,
      description: `Train is ${Math.abs(mileageBalance).toLocaleString()}km ${
        mileageBalance < 0 ? 'under' : 'over'
      } target mileage`,
    });

    // Depot preference explanation
    if (train.homeDepotId !== train.currentDepotId) {
      const depotImpact = input.config.softConstraintPenalties.preferenceViolation;
      explanation.push({
        constraintType: 'SOFT',
        constraintName: 'DEPOT_PREFERENCE',
        impact: depotImpact,
        description: `Train is away from home depot`,
      });
    }

    // Route expected km explanation (detailed mode)
    if (verbosity === 'DETAILED') {
      explanation.push({
        constraintType: 'SOFT',
        constraintName: 'ROUTE_UTILIZATION',
        impact: 0,
        description: `Route ${route.routeCode} expected to add ${route.expectedKmPerDay}km`,
      });
    }

    // Soft constraint penalties from input
    for (const constraint of input.softConstraints) {
      if (constraint.trainId === train.id) {
        explanation.push({
          constraintType: 'SOFT',
          constraintName: constraint.type,
          impact: constraint.penaltyWeight,
          description: constraint.description,
        });
      }
    }

    return explanation;
  }

  /**
   * Calculate assignment score (lower is better)
   */
  private calculateScore(
    train: OptimizerTrainInput,
    route: OptimizerRouteInput,
    input: OptimizerFullInput,
    explanation: ExplanationTrace[]
  ): number {
    // Base score from soft constraint impacts
    let score = explanation.reduce((sum, exp) => {
      if (exp.constraintType === 'SOFT') {
        return sum + Math.abs(exp.impact);
      }
      return sum;
    }, 0);

    // Bonus for under-utilized trains (negative balance = lower score)
    const mileageBalance = train.currentMileageKm - train.targetMileageKm;
    if (mileageBalance < 0) {
      score -= Math.abs(mileageBalance) / 100;
    }

    // Penalty for high-mileage trains
    if (mileageBalance > 0) {
      score += mileageBalance / 50;
    }

    return Math.round(score * 100) / 100;
  }

  /**
   * Calculate total penalty across all assignments
   */
  private calculateTotalPenalty(assignments: Assignment[]): number {
    return assignments.reduce((sum, a) => sum + a.score, 0);
  }

  /**
   * Find blocking reason for unassigned train
   */
  private findBlockingReason(
    train: OptimizerTrainInput,
    input: OptimizerFullInput,
    unavailableTrainIds: Set<string>,
    trainConstraintMap: Map<string, string[]>
  ): string {
    if (train.fitnessStatus !== 'FIT') {
      return `Train is ${train.fitnessStatus}`;
    }

    if (unavailableTrainIds.has(train.id)) {
      const event = input.unavailabilityEvents?.find(
        (e) => e.trainId === train.id && e.status === 'ACTIVE'
      );
      return `Unavailable: ${event?.eventType || 'CM event'}`;
    }

    const constraints = trainConstraintMap.get(train.id);
    if (constraints && constraints.length > 0) {
      return constraints[0];
    }

    return 'No compatible route available or all routes fully staffed';
  }

  /**
   * Get list of blocking constraints for a train
   */
  private getBlockingConstraints(
    train: OptimizerTrainInput,
    input: OptimizerFullInput,
    trainConstraintMap: Map<string, string[]>
  ): string[] {
    const constraints: string[] = [];

    if (train.fitnessStatus !== 'FIT') {
      constraints.push(`FITNESS: ${train.fitnessStatus}`);
    }

    const hardConstraints = trainConstraintMap.get(train.id);
    if (hardConstraints) {
      constraints.push(...hardConstraints.map((c) => `HARD: ${c}`));
    }

    const activeEvent = input.unavailabilityEvents?.find(
      (e) => e.trainId === train.id && e.status === 'ACTIVE'
    );
    if (activeEvent) {
      constraints.push(`UNAVAILABLE: ${activeEvent.eventType}`);
    }

    return constraints;
  }

  /**
   * Check material warnings for pending PMs
   */
  private checkMaterialWarnings(input: OptimizerFullInput): MaterialWarning[] {
    const warnings: MaterialWarning[] = [];

    if (!input.pendingPms || !input.materialPositions) {
      return warnings;
    }

    const trainMap = new Map(input.trains.map((t) => [t.id, t]));
    const today = new Date(input.assignmentDate);
    const warningThresholdDays = 14;

    for (const pm of input.pendingPms) {
      const train = trainMap.get(pm.trainId);
      if (!train) continue;

      const pmDate = new Date(pm.targetDate);
      const daysUntilPm = Math.ceil(
        (pmDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
      );

      for (const mat of pm.requiredMaterials) {
        if (mat.criticality !== 'BLOCKING') continue;

        const position = input.materialPositions.find(
          (p) =>
            p.partNumber === mat.partNumber && p.depotId === train.homeDepotId
        );

        if (!position || position.quantityAvailable < mat.quantity) {
          // Check if delivery will arrive in time
          if (position?.nextDeliveryDate) {
            const deliveryDate = new Date(position.nextDeliveryDate);
            if (deliveryDate > pmDate) {
              warnings.push({
                pmId: pm.pmId,
                trainId: pm.trainId,
                partNumber: mat.partNumber,
                status: 'ARRIVING_LATE',
                description: `Part ${mat.partNumber} delivery expected ${position.nextDeliveryDate}, after PM date ${pm.targetDate}`,
              });
            }
          } else if (daysUntilPm <= warningThresholdDays) {
            warnings.push({
              pmId: pm.pmId,
              trainId: pm.trainId,
              partNumber: mat.partNumber,
              status: position ? 'LOW_STOCK' : 'UNAVAILABLE',
              description: `Part ${mat.partNumber} unavailable at depot, ${
                mat.quantity
              } required, ${position?.quantityAvailable || 0} available`,
            });
          }
        }
      }
    }

    return warnings;
  }

  /**
   * Validate service demand constraints
   */
  private validateServiceDemand(
    input: OptimizerFullInput,
    assignments: Assignment[],
    unassigned: UnassignedTrain[]
  ): void {
    if (!input.serviceDemand) return;

    // Count assigned trains per fleet
    const trainMap = new Map(input.trains.map((t) => [t.id, t]));
    const assignedByFleet = new Map<string, number>();

    for (const assignment of assignments) {
      const train = trainMap.get(assignment.trainId);
      if (train) {
        const count = assignedByFleet.get(train.fleetId) || 0;
        assignedByFleet.set(train.fleetId, count + 1);
      }
    }

    // Check each fleet's service demand
    for (const demand of input.serviceDemand) {
      const assigned = assignedByFleet.get(demand.fleetId) || 0;
      if (assigned < demand.minTrainsRequired) {
        unassigned.push({
          reason: `Service demand violation: Fleet ${demand.fleetId} requires ${demand.minTrainsRequired} trains, only ${assigned} assigned`,
          blockingConstraints: [
            `SERVICE_DEMAND: ${demand.minTrainsRequired} required`,
            `AVAILABLE: ${assigned} assigned`,
          ],
        });

        this.log.warn(
          {
            fleetId: demand.fleetId,
            required: demand.minTrainsRequired,
            assigned,
            dayType: demand.dayType,
          },
          'Service demand violation detected'
        );
      }
    }
  }
}

// Export singleton instance
export const fallbackOptimizer = new FallbackOptimizer();

