/**
 * MMS Run Assignment Optimizer
 *
 * Entry point for the C++ OR-Tools CP-SAT optimizer.
 * Communicates with TypeScript wrapper via NDJSON on stdin/stdout.
 *
 * Usage:
 *   echo '{"request_id":"...", "trains":[...], "routes":[...]}' | ./mms-optimizer
 *
 * Protocol:
 *   - Input: Single JSON object on stdin (newline-terminated)
 *   - Output: NDJSON stream on stdout (HEARTBEAT, PROGRESS, ERROR, RESULT)
 *
 * @see specs/004-domain-services.md Section 4.3
 */

#include "ipc.h"
#include "solver.h"
#include <iostream>
#include <csignal>
#include <cstdlib>

// Global IPC handler for signal handling
static mms::IpcHandler* g_ipc = nullptr;
static std::string g_requestId;

/**
 * Signal handler for SIGSEGV, SIGABRT, SIGFPE
 */
void signalHandler(int signal) {
    if (g_ipc) {
        mms::ErrorCode code = mms::ErrorCode::INTERNAL_ERROR;
        std::string message;

        switch (signal) {
            case SIGSEGV:
                code = mms::ErrorCode::SEGFAULT;
                message = "Segmentation fault in optimizer";
                break;
            case SIGABRT:
                code = mms::ErrorCode::INTERNAL_ERROR;
                message = "Abort signal received";
                break;
            case SIGFPE:
                code = mms::ErrorCode::INTERNAL_ERROR;
                message = "Floating point exception";
                break;
            default:
                message = "Unknown signal received: " + std::to_string(signal);
                break;
        }

        // Try to send error before exiting
        try {
            g_ipc->sendError(g_requestId, code, message);
        } catch (...) {
            // Can't do much if error reporting fails
            std::cerr << "FATAL: " << message << std::endl;
            std::exit(128 + signal);
        }
    }

    std::exit(128 + signal);
}

/**
 * Setup signal handlers
 */
void setupSignalHandlers() {
    std::signal(SIGSEGV, signalHandler);
    std::signal(SIGABRT, signalHandler);
    std::signal(SIGFPE, signalHandler);

    // Ignore SIGPIPE (broken pipe when parent dies)
    std::signal(SIGPIPE, SIG_IGN);
}

/**
 * Main entry point
 */
int main(int argc, char* argv[]) {
    // Handle --version flag
    if (argc > 1 && std::string(argv[1]) == "--version") {
        std::cout << "mms-optimizer 1.0.0" << std::endl;
        std::cout << "OR-Tools CP-SAT Solver" << std::endl;
        return 0;
    }

    // Handle --help flag
    if (argc > 1 && (std::string(argv[1]) == "--help" || std::string(argv[1]) == "-h")) {
        std::cout << "MMS Run Assignment Optimizer" << std::endl;
        std::cout << std::endl;
        std::cout << "Usage: " << argv[0] << " < input.json" << std::endl;
        std::cout << std::endl;
        std::cout << "Reads JSON input from stdin, outputs NDJSON to stdout." << std::endl;
        std::cout << std::endl;
        std::cout << "Options:" << std::endl;
        std::cout << "  --version    Show version information" << std::endl;
        std::cout << "  --help, -h   Show this help message" << std::endl;
        return 0;
    }

    // Create IPC handler
    mms::IpcHandler ipc;
    g_ipc = &ipc;

    // Setup signal handlers
    setupSignalHandlers();

    try {
        // Read input from stdin
        mms::json input = ipc.readInput();

        // Extract request ID for error handling
        if (input.contains("request_id")) {
            g_requestId = input["request_id"].get<std::string>();
        } else {
            g_requestId = "unknown";
        }

        // Start heartbeat thread
        ipc.startHeartbeatThread(g_requestId, 5000);

        // Create solver
        mms::MmsSolver solver;

        // Validate input
        std::string validationError = solver.validateInput(input);
        if (!validationError.empty()) {
            ipc.sendError(
                g_requestId,
                mms::ErrorCode::INVALID_INPUT,
                validationError,
                "",
                "Check input JSON structure matches expected schema"
            );
            // sendError exits, so this is unreachable
        }

        // Solve with progress callback
        mms::SolverResult result = solver.solve(input,
            [&ipc, &g_requestId](double percent, double objective, bool feasible) {
                ipc.sendProgress(g_requestId, percent, objective, feasible, ipc.getElapsedMs());
            }
        );

        // Send result
        ipc.sendResult(result.toJson());

        return 0;

    } catch (const std::exception& e) {
        ipc.sendError(
            g_requestId,
            mms::ErrorCode::INTERNAL_ERROR,
            std::string("Exception: ") + e.what()
        );
        // sendError exits, so this is unreachable
    } catch (...) {
        ipc.sendError(
            g_requestId,
            mms::ErrorCode::INTERNAL_ERROR,
            "Unknown exception occurred"
        );
        // sendError exits, so this is unreachable
    }

    return 1;
}

