/**
 * MMS Run Assignment Solver
 *
 * CP-SAT solver for train-to-route assignment optimization.
 * Uses Google OR-Tools for constraint programming.
 *
 * @see specs/004-domain-services.md Section 4.3.3
 */

#pragma once

#include <nlohmann/json.hpp>
#include <string>
#include <vector>
#include <unordered_map>
#include <functional>
#include <optional>

namespace mms {

using json = nlohmann::json;

/**
 * Explanation factor for assignment decisions
 */
struct ExplanationFactor {
    std::string constraintType;  // "HARD" or "SOFT"
    std::string constraintName;
    double impact;
    std::string description;

    json toJson() const;
};

/**
 * Train-to-route assignment result
 */
struct Assignment {
    std::string trainId;
    std::string routeId;
    double score;
    std::vector<ExplanationFactor> explanation;

    json toJson() const;
};

/**
 * Unassigned train or unfilled route
 */
struct Unassigned {
    std::optional<std::string> trainId;
    std::optional<std::string> routeId;
    std::optional<int> shortfall;
    std::string reason;
    std::vector<std::string> blockingConstraints;

    json toJson() const;
};

/**
 * Material warning for pending PM
 */
struct MaterialWarning {
    std::string pmId;
    std::string trainId;
    std::string partNumber;
    std::string status;  // UNAVAILABLE, LOW_STOCK, ARRIVING_LATE
    std::string description;

    json toJson() const;
};

/**
 * Result summary
 */
struct ResultSummary {
    double totalPenalty;
    int trainsAssigned;
    int trainsUnassigned;
    std::unordered_map<std::string, double> softConstraintBreakdown;
    int materialBlocks;

    json toJson() const;
};

/**
 * Optimization result
 */
struct SolverResult {
    std::string requestId;
    std::string status;  // OPTIMAL, FEASIBLE, INFEASIBLE
    int64_t solveTimeMs;
    std::vector<Assignment> assignments;
    std::vector<Unassigned> unassigned;
    std::vector<MaterialWarning> materialWarnings;
    ResultSummary summary;

    json toJson() const;
};

/**
 * Progress callback function type
 * @param percent Progress percentage (0-100)
 * @param objective Current objective value
 * @param feasible Whether current solution is feasible
 */
using ProgressCallback = std::function<void(double percent, double objective, bool feasible)>;

/**
 * MMS Run Assignment Solver
 *
 * Optimizes train-to-route assignments using CP-SAT.
 */
class MmsSolver {
public:
    MmsSolver();
    ~MmsSolver() = default;

    /**
     * Solve the run assignment optimization problem
     *
     * @param input JSON input containing trains, routes, and constraints
     * @param onProgress Optional progress callback
     * @return Optimization result
     */
    SolverResult solve(const json& input, ProgressCallback onProgress = nullptr);

    /**
     * Validate input JSON structure
     *
     * @param input Input JSON
     * @return Error message if invalid, empty if valid
     */
    std::string validateInput(const json& input) const;

private:
    // Input parsing
    struct Train {
        std::string id;
        std::string trainNumber;
        std::string fleetId;
        int currentMileage;
        int targetMileage;
        std::string fitnessStatus;
        std::vector<std::string> restrictions;
        std::string homeDepotId;
        std::string currentDepotId;
    };

    struct Route {
        std::string id;
        std::string routeCode;
        int expectedKm;
        int requiredTrains;
        std::vector<std::string> allowedFleets;
        std::vector<std::string> restrictions;
    };

    struct HardConstraint {
        std::string type;
        std::string trainId;
        std::optional<std::string> routeId;
        std::string description;
    };

    struct SoftConstraint {
        std::string type;
        std::string trainId;
        int penaltyWeight;
        std::string description;
    };

    struct UnavailabilityEvent {
        std::string trainId;
        std::string eventType;
        std::string status;
        bool blocksRunAssignment;
        std::string description;
    };

    struct RouteCompatibility {
        std::optional<std::string> trainId;
        std::optional<std::string> fleetId;
        std::string routeId;
        bool isCompatible;
        std::string constraintType;
        std::string restrictionReason;
    };

    struct Config {
        int maxSolveTimeSeconds = 30;
        int numWorkers = 4;
        int mileageImbalancePenalty = 100;
        int preferenceViolationPenalty = 50;
        int overtimeHoursPenalty = 200;
        std::string explanationVerbosity = "STANDARD";
    };

    // Parse input JSON
    std::vector<Train> parseTrains(const json& input);
    std::vector<Route> parseRoutes(const json& input);
    std::vector<HardConstraint> parseHardConstraints(const json& input);
    std::vector<SoftConstraint> parseSoftConstraints(const json& input);
    std::vector<UnavailabilityEvent> parseUnavailabilityEvents(const json& input);
    std::vector<RouteCompatibility> parseRouteCompatibility(const json& input);
    Config parseConfig(const json& input);

    // Find train/route index by ID
    size_t findTrainIndex(const std::vector<Train>& trains, const std::string& id) const;
    size_t findRouteIndex(const std::vector<Route>& routes, const std::string& id) const;

    // Check fleet compatibility
    bool isFleetAllowed(const Train& train, const Route& route) const;

    // Generate explanation for assignment
    std::vector<ExplanationFactor> generateExplanation(
        const Train& train,
        const Route& route,
        const json& input,
        double objectiveValue
    ) const;

    // Find unassigned trains/routes
    std::vector<Unassigned> findUnassigned(
        const std::vector<Train>& trains,
        const std::vector<Route>& routes,
        const std::vector<Assignment>& assignments,
        const json& input
    ) const;

    // Check material warnings
    std::vector<MaterialWarning> checkMaterialWarnings(const json& input) const;

    // Build result summary
    ResultSummary buildSummary(
        const std::vector<Assignment>& assignments,
        const std::vector<Unassigned>& unassigned,
        double totalPenalty
    ) const;
};

} // namespace mms

/**
 * MMS Optimizer IPC Protocol
 *
 * Handles NDJSON communication with the TypeScript wrapper.
 * Protocol:
 *   - Input: Single JSON object on stdin (newline-terminated)
 *   - Output: NDJSON stream on stdout (HEARTBEAT, PROGRESS, ERROR, RESULT)
 *
 * @see specs/004-domain-services.md Section 4.3.2
 */

#pragma once

#include <nlohmann/json.hpp>
#include <string>
#include <chrono>
#include <thread>
#include <atomic>
#include <mutex>

namespace mms {

using json = nlohmann::json;

/**
 * Message types sent to stdout
 */
enum class MessageType {
    HEARTBEAT,
    PROGRESS,
    ERROR,
    RESULT
};

/**
 * Error codes for ERROR messages
 */
enum class ErrorCode {
    SEGFAULT,
    TIMEOUT,
    OOM,
    INVALID_INPUT,
    INTERNAL_ERROR
};

/**
 * IPC Handler for NDJSON communication
 *
 * Thread-safe output handling with heartbeat support.
 */
class IpcHandler {
public:
    IpcHandler();
    ~IpcHandler();

    // Prevent copying
    IpcHandler(const IpcHandler&) = delete;
    IpcHandler& operator=(const IpcHandler&) = delete;

    /**
     * Read input from stdin
     * @return Parsed JSON input or throws on invalid JSON
     */
    json readInput();

    /**
     * Send heartbeat message
     * @param requestId Request ID for correlation
     * @param memoryMb Current memory usage in MB
     * @param threadCount Number of active threads
     * @param branchesPerSecond Solver branches per second
     */
    void sendHeartbeat(
        const std::string& requestId,
        double memoryMb,
        int threadCount,
        double branchesPerSecond
    );

    /**
     * Send progress update
     * @param requestId Request ID for correlation
     * @param percent Progress percentage (0-100)
     * @param currentObjective Current objective value
     * @param feasible Whether current solution is feasible
     * @param elapsedMs Elapsed time in milliseconds
     */
    void sendProgress(
        const std::string& requestId,
        double percent,
        double currentObjective,
        bool feasible,
        int64_t elapsedMs
    );

    /**
     * Send error message and exit
     * @param requestId Request ID for correlation
     * @param code Error code
     * @param message Error message
     * @param stackTrace Optional stack trace
     * @param recoverySuggestion Suggestion for recovery
     */
    [[noreturn]] void sendError(
        const std::string& requestId,
        ErrorCode code,
        const std::string& message,
        const std::string& stackTrace = "",
        const std::string& recoverySuggestion = ""
    );

    /**
     * Send result and exit successfully
     * @param result Complete result JSON object
     */
    void sendResult(const json& result);

    /**
     * Start background heartbeat thread
     * @param requestId Request ID for correlation
     * @param intervalMs Heartbeat interval in milliseconds
     */
    void startHeartbeatThread(const std::string& requestId, int intervalMs = 5000);

    /**
     * Stop background heartbeat thread
     */
    void stopHeartbeatThread();

    /**
     * Update progress info for heartbeat thread
     */
    void updateProgress(double percent, double objective, bool feasible);

    /**
     * Get elapsed time since start
     */
    int64_t getElapsedMs() const;

private:
    /**
     * Send JSON message to stdout (thread-safe)
     */
    void sendMessage(const json& msg);

    /**
     * Get current memory usage in MB
     */
    double getMemoryUsageMb() const;

    /**
     * Heartbeat thread function
     */
    void heartbeatLoop(const std::string& requestId, int intervalMs);

    std::mutex outputMutex_;
    std::atomic<bool> heartbeatRunning_{false};
    std::thread heartbeatThread_;

    // Progress state for heartbeat
    std::atomic<double> lastPercent_{0.0};
    std::atomic<double> lastObjective_{0.0};
    std::atomic<bool> lastFeasible_{false};
    std::atomic<int64_t> branchesExplored_{0};

    std::chrono::steady_clock::time_point startTime_;
};

/**
 * Convert ErrorCode to string
 */
std::string errorCodeToString(ErrorCode code);

} // namespace mms

