/**
 * MMS Optimizer IPC Protocol Implementation
 */

#include "ipc.h"
#include <iostream>
#include <sstream>
#include <cstring>
#include <csignal>

#ifdef __linux__
#include <sys/resource.h>
#elif __APPLE__
#include <mach/mach.h>
#endif

namespace mms {

IpcHandler::IpcHandler()
    : startTime_(std::chrono::steady_clock::now())
{
}

IpcHandler::~IpcHandler() {
    stopHeartbeatThread();
}

json IpcHandler::readInput() {
    std::string line;
    if (!std::getline(std::cin, line)) {
        throw std::runtime_error("Failed to read input from stdin");
    }

    try {
        return json::parse(line);
    } catch (const json::parse_error& e) {
        throw std::runtime_error(
            std::string("Invalid JSON input: ") + e.what()
        );
    }
}

void IpcHandler::sendHeartbeat(
    const std::string& requestId,
    double memoryMb,
    int threadCount,
    double branchesPerSecond
) {
    json msg;
    msg["type"] = "HEARTBEAT";
    msg["request_id"] = requestId;
    msg["timestamp"] = std::chrono::duration_cast<std::chrono::milliseconds>(
        std::chrono::system_clock::now().time_since_epoch()
    ).count();
    msg["memory_mb"] = memoryMb;
    msg["thread_count"] = threadCount;
    msg["branches_per_second"] = branchesPerSecond;

    sendMessage(msg);
}

void IpcHandler::sendProgress(
    const std::string& requestId,
    double percent,
    double currentObjective,
    bool feasible,
    int64_t elapsedMs
) {
    // Update state for heartbeat thread
    lastPercent_.store(percent);
    lastObjective_.store(currentObjective);
    lastFeasible_.store(feasible);

    json msg;
    msg["type"] = "PROGRESS";
    msg["request_id"] = requestId;
    msg["percent"] = percent;
    msg["current_objective"] = currentObjective;
    msg["feasible"] = feasible;
    msg["elapsed_ms"] = elapsedMs;

    sendMessage(msg);
}

void IpcHandler::sendError(
    const std::string& requestId,
    ErrorCode code,
    const std::string& message,
    const std::string& stackTrace,
    const std::string& recoverySuggestion
) {
    stopHeartbeatThread();

    json msg;
    msg["type"] = "ERROR";
    msg["request_id"] = requestId;
    msg["error_code"] = errorCodeToString(code);
    msg["error_message"] = message;

    if (!stackTrace.empty()) {
        msg["stack_trace"] = stackTrace;
    }

    json lastProgress;
    lastProgress["percent"] = lastPercent_.load();
    lastProgress["branches_explored"] = branchesExplored_.load();
    lastProgress["memory_mb"] = getMemoryUsageMb();
    msg["last_progress"] = lastProgress;

    if (!recoverySuggestion.empty()) {
        msg["recovery_suggestion"] = recoverySuggestion;
    } else {
        // Default recovery suggestions based on error code
        switch (code) {
            case ErrorCode::TIMEOUT:
                msg["recovery_suggestion"] = "Consider increasing max_solve_time_seconds or simplifying the problem";
                break;
            case ErrorCode::OOM:
                msg["recovery_suggestion"] = "Reduce problem size or increase container memory limits";
                break;
            case ErrorCode::INVALID_INPUT:
                msg["recovery_suggestion"] = "Validate input JSON schema and constraint consistency";
                break;
            default:
                msg["recovery_suggestion"] = "Check logs for details and retry";
                break;
        }
    }

    sendMessage(msg);

    // Exit with non-zero code for error
    std::exit(1);
}

void IpcHandler::sendResult(const json& result) {
    stopHeartbeatThread();
    sendMessage(result);
}

void IpcHandler::startHeartbeatThread(const std::string& requestId, int intervalMs) {
    if (heartbeatRunning_.load()) {
        return; // Already running
    }

    heartbeatRunning_.store(true);
    heartbeatThread_ = std::thread(&IpcHandler::heartbeatLoop, this, requestId, intervalMs);
}

